  1	import { type FC, useCallback, useMemo, useState } from 'react';
  2	import { useWatch } from 'react-hook-form';
  3	import { useInventoryVms } from 'src/modules/Providers/views/details/tabs/VirtualMachines/utils/hooks/useInventoryVms';
  4	
  5	import {
  6	  Button,
  7	  ButtonVariant,
  8	  Modal,
  9	  ModalVariant,
 10	  useWizardContext,
 11	} from '@patternfly/react-core';
 12	import { isEmpty } from '@utils/helpers';
 13	import { useForkliftTranslation } from '@utils/i18n';
 14	
 15	import { PlanWizardStepId } from '../../constants';
 16	import CreatePlanWizardFooter from '../../CreatePlanWizardFooter';
 17	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
 18	import { useStepValidation } from '../../hooks/useStepValidation';
 19	import type { ProviderVirtualMachine } from '../../types';
 20	import { GeneralFormFieldId } from '../general-information/constants';
 21	
 22	import { VmFormFieldId } from './constants';
 23	import { getVmsWithCriticalConcerns, hasCriticalConcern } from './utils';
 24	import VirtualMachinesTable from './VirtualMachinesTable';
 25	
 26	const VirtualMachinesStepFooter: FC = () => {
 27	  const { t } = useForkliftTranslation();
 28	  const [isModalOpen, setIsModalOpen] = useState(false);
 29	  const [pendingVmIds, setPendingVmIds] = useState<string[]>();
 30	  const { goToNextStep } = useWizardContext();
 31	  const { control, setValue, trigger } = useCreatePlanFormContext();
 32	  const { validateStep } = useStepValidation();
 33	  const [sourceProvider, selectedVms] = useWatch({
 34	    control,
 35	    name: [GeneralFormFieldId.SourceProvider, VmFormFieldId.Vms],
 36	  });
 37	  const [vmInventoryData] = useInventoryVms({ provider: sourceProvider });
 38	  const vmsWithCriticalIssues = getVmsWithCriticalConcerns(selectedVms);
 39	
 40	  const pendingVms = useMemo(
 41	    () =>
 42	      pendingVmIds
 43	        ? Object.fromEntries(pendingVmIds.map((id) => [id, selectedVms[id]]))
 44	        : vmsWithCriticalIssues,
 45	    [pendingVmIds, selectedVms, vmsWithCriticalIssues],
 46	  );
 47	
 48	  // Get VM data for the critical concern VMs to display in modal
 49	  const criticalVmData = useMemo(
 50	    () => vmInventoryData.filter(({ vm }) => hasCriticalConcern(vm) && vm.id in selectedVms),
 51	    [vmInventoryData, selectedVms],
 52	  );
 53	
 54	  // Validate form and handle next step or show warning modal
 55	  const handleNextStep = useCallback(async () => {
 56	    const isValid = await validateStep(PlanWizardStepId.VirtualMachines);
 57	
 58	    if (isValid) {
 59	      // Skip modal if no critical issues found
 60	      if (isEmpty(Object.keys(vmsWithCriticalIssues))) {
 61	        await goToNextStep();
 62	        return;
 63	      }
 64	
 65	      // Show warning modal for VMs with critical issues
 66	      setIsModalOpen(true);
 67	    }
 68	  }, [validateStep, vmsWithCriticalIssues, goToNextStep]);
 69	
 70	  const closeModal = useCallback(() => {
 71	    setIsModalOpen(false);
 72	    setPendingVmIds(undefined);
 73	  }, []);
 74	
 75	  // Handle VM selection updates and navigation
 76	  const updateVmSelectionAndProceed = useCallback(
 77	    async (vms: Record<string, ProviderVirtualMachine>) => {
 78	      setValue(VmFormFieldId.Vms, vms);
 79	      closeModal();
 80	
 81	      if (isEmpty(vms)) {
 82	        await trigger(VmFormFieldId.Vms);
 83	        return;
 84	      }
 85	
 86	      await goToNextStep();
 87	    },
 88	    [closeModal, goToNextStep, setValue, trigger],
 89	  );
 90	
 91	  // Confirm selection including pending VMs from modal
 92	  const confirmSelection = useCallback(async () => {
 93	    const nonCriticalVms = Object.fromEntries(
 94	      Object.entries(selectedVms).filter(([_, vm]) => !hasCriticalConcern(vm)),
 95	    );
 96	
 97	    // Combine non-critical VMs with user's staged selections
 98	    const updatedVmSelections = {
 99	      ...nonCriticalVms,
100	      ...pendingVms,
101	    };
102	
103	    await updateVmSelectionAndProceed(updatedVmSelections);
104	  }, [selectedVms, pendingVms, updateVmSelectionAndProceed]);
105	
106	  // Remove all VMs with critical issues and proceed
107	  const deselectCriticalVms = useCallback(async () => {
108	    const updatedVmSelections = { ...selectedVms };
109	    const criticalVmIds = Object.keys(vmsWithCriticalIssues);
110	
111	    for (const vmId of criticalVmIds) {
112	      delete updatedVmSelections[vmId];
113	    }
114	
115	    await updateVmSelectionAndProceed(updatedVmSelections);
116	  }, [selectedVms, vmsWithCriticalIssues, updateVmSelectionAndProceed]);
117	
118	  // Handle VM selection changes in the modal
119	  const handleVmSelectionChange = useCallback((vms: Record<string, ProviderVirtualMachine>) => {
120	    setPendingVmIds(Object.keys(vms));
121	  }, []);
122	
123	  return (
124	    <>
125	      <CreatePlanWizardFooter onNext={handleNextStep} />
126	
127	      {isModalOpen && (
128	        <Modal
129	          isOpen
130	          variant={ModalVariant.large}
131	          title={t('Confirm selections with critical issues')}
132	          titleIconVariant="danger"
133	          description={t(
134	            'Critical issues detected in your selected VMs will cause the migration to fail. Resolve these issues or remove the VMs from the plan before starting the migration.',
135	          )}
136	          onClose={closeModal}
137	          actions={[
138	            <Button key="confirm" onClick={confirmSelection}>
139	              {t('Confirm selections')}
140	            </Button>,
141	            <Button key="deselect" variant={ButtonVariant.secondary} onClick={deselectCriticalVms}>
142	              {t('Deselect critical issue VMs')}
143	            </Button>,
144	            <Button key="cancel" variant={ButtonVariant.secondary} onClick={closeModal}>
145	              {t('Cancel')}
146	            </Button>,
147	          ]}
148	        >
149	          <VirtualMachinesTable
150	            vmData={criticalVmData}
151	            initialSelectedIds={Object.keys(vmsWithCriticalIssues)}
152	            value={pendingVms}
153	            isSelectable
154	            onChange={handleVmSelectionChange}
155	            hasCriticalConcernFilter
156	          />
157	        </Modal>
158	      )}
159	    </>
160	  );
161	};
162	
163	export default VirtualMachinesStepFooter;

